// Cache para evitar llamadas repetidas al API de contactos
const contactEmailCache = {};

// Busca un contacto en Lemlist por LinkedIn URL
// Intenta multiples endpoints: api.lemlist.com y app.lemlist.com
async function findContactByLinkedIn(profileUrl) {
  const normalized = normalizeLinkedinUrl(profileUrl);
  if (!normalized) return null;

  if (Object.prototype.hasOwnProperty.call(contactEmailCache, normalized)) {
    return contactEmailCache[normalized];
  }

  const slug = normalized.replace('linkedin.com/in/', '');
  const auth = { username: '', password: LEMLIST_API_KEY };

  // Attempt 1: api.lemlist.com/api/contacts with Basic auth
  try {
    const r1 = await axios.get('https://api.lemlist.com/api/contacts', {
      auth,
      params: { search: slug, limit: 10 },
      timeout: 8000
    });
    const contacts = Array.isArray(r1.data) ? r1.data : (Array.isArray(r1.data?.contacts) ? r1.data.contacts : []);
    let found = contacts.find(c => normalizeLinkedinUrl(c.linkedinUrl || c.linkedin || c.linkedInUrl || '') === normalized);
    if (!found && contacts.length === 1) found = contacts[0];
    if (found?.email) {
      contactEmailCache[normalized] = found.email;
      console.log('   [A1] Contacto encontrado: ' + found.email);
      return found.email;
    }
  } catch (e1) {
    console.log('   [A1] api.lemlist.com/contacts: ' + e1.message.slice(0, 80));
  }

  // Attempt 2: api.lemlist.com/api/leads with search param
  try {
    const r2 = await axios.get('https://api.lemlist.com/api/leads', {
      auth,
      params: { search: slug, limit: 10 },
      timeout: 8000
    });
    const leads = Array.isArray(r2.data) ? r2.data : [];
    let found = leads.find(l => normalizeLinkedinUrl(l.linkedinUrl || l.linkedin || '') === normalized);
    if (!found && leads.length === 1) found = leads[0];
    if (found?.email) {
      contactEmailCache[normalized] = found.email;
      console.log('   [A2] Lead encontrado: ' + found.email);
      return found.email;
    }
  } catch (e2) {
    console.log('   [A2] api.lemlist.com/leads: ' + e2.message.slice(0, 80));
  }

  contactEmailCache[normalized] = null;
  return null;
}

// Resuelve el email de un lead dado su profileUrl de LinkedIn
async function resolveEmailFromLinkedIn(profileUrl) {
  return await findContactByLinkedIn(profileUrl);
}


